/* 状态机架构定义 —— 接口层（信息隐藏） */

typedef enum {
    STATE_IDLE = 0,
    STATE_SYNC,
    STATE_ADDR,
    STATE_CMD,
    STATE_DATA,
    STATE_CRC_CHECK,
    STATE_ACK,
    STATE_NACK,
    STATE_COUNT /* 用于编译器 -Wswitch-enum 检查 */
} protocol_state_t;

typedef enum {
    EVT_FRAME_START = 0,
    EVT_BYTE_RECEIVED,
    EVT_CRC_PASS,
    EVT_CRC_FAIL,
    EVT_TIMEOUT,
    EVT_RESET
} protocol_event_t;

/* 对外接口 —— 调用者只看到这三个函数 */
void protocol_init(void);
void protocol_event(protocol_event_t evt);
protocol_state_t protocol_get_state(void);

/* 内部实现 —— 调用者不可见 */
static protocol_state_t current_state = STATE_IDLE;
static uint8_t frame_buffer[256];
static uint16_t buffer_idx = 0;

static volatile protocol_state_t current_state = STATE_IDLE;
static uint8_t  event_received = 0;  /* 中断设置，主循环读取 */
static protocol_event_t last_event;

/* 中断：收到 UART 字节时设置事件标志 */
void USART1_IRQHandler(void) {
    if (USART1->SR & USART_SR_RXNE) {
        last_event = EVT_BYTE_RECEIVED;
        event_received = 1;
        USART1->SR &= ~USART_SR_RXNE;  /* 清除标志 */
    }
}

/* 主循环：非阻塞事件处理 */
void handle_event(void) {
    if (!event_received) return;
    event_received = 0;

    switch (current_state) {
    case STATE_IDLE:
        if (last_event == EVT_FRAME_START) {
            buffer_idx = 0;
            current_state = STATE_SYNC;
        }
        break;

    case STATE_SYNC:
        if (last_event == EVT_BYTE_RECEIVED) {
            frame_buffer[buffer_idx++] = USART1->DR;
            if (buffer_idx >= 3 && frame_buffer[0] == 0xAA && frame_buffer[1] == 0x55) {
                current_state = STATE_ADDR;
            } else if (buffer_idx >= 4) {
                buffer_idx = 0;
            }
        }
        break;

    case STATE_ADDR:
    case STATE_CMD:
        if (last_event == EVT_BYTE_RECEIVED) {
            frame_buffer[buffer_idx++] = USART1->DR;
            current_state = (current_state == STATE_ADDR) ? STATE_CMD : STATE_DATA;
        }
        break;

    default:
        /* 未知状态：重置到 IDLE，避免死锁 */
        current_state = STATE_IDLE;
        buffer_idx = 0;
        break;
    }
}

/* 改进方案：带超时和事件队列的状态机框架 */

typedef struct {
    protocol_event_t events[8];  /* 环形事件队列，容量 8 */
    volatile uint16_t head;      /* 写入位置 */
    volatile uint16_t tail;      /* 读取位置 */
    volatile uint32_t tick;      /* 当前系统 Tick */
} event_queue_t;

static event_queue_t eq;

/* 入队：线程/中断安全 */
void eq_push(protocol_event_t evt) {
    uint16_t next = (eq.head + 1) % 8;
    if (next != eq.tail) {  /* 队列未满 */
        eq.events[eq.head] = evt;
        eq.head = next;
    }
    /* 队列满时静默丢弃——比丢失事件好 */
}

/* 出队：返回最新事件，NULL 表示空 */
protocol_event_t *eq_pop(void) {
    if (eq.head == eq.tail) return NULL;
    static protocol_event_t result;
    result = eq.events[eq.tail];
    eq.tail = (eq.tail + 1) % 8;
    return &result;
}

/* 超时检查：在每个 case 中调用 */
static int check_timeout(uint32_t enter_tick, uint32_t max_ms) {
    return (get_tick_count() - enter_tick) > max_ms;
}

/* ===== 重构前：goto 状态机（坏味道：分散的控制流） ===== */
void device_manager_run(void) {
    connect_to_server();
    goto AUTHENTICATE;

AUTHENTICATE:
    if (auth_success()) {
        goto CONNECTED;
    } else if (auth_retry_count++ > 3) {
        goto ERROR;
    } else {
        goto AUTHENTICATE;
    }

CONNECTED:
    while (1) {
        if (data_available()) {
            process_data();
            if (should_disconnect()) goto DISCONNECT;
        }
        if (heartbeat_timeout()) goto RECONNECT;
    }

RECONNECT:
    disconnect_from_server();
    connect_to_server();
    goto AUTHENTICATE;

DISCONNECT:
    cleanup_resources();
    goto IDLE;

ERROR:
    log_error("Fatal error");
    while (1) {}  /* 死循环 */

IDLE:
    ;  /* 空闲等待 */
}

/* ===== 重构后：enum + switch 状态机（清晰的结构） ===== */
typedef enum { DEV_IDLE, DEV_CONNECTING, DEV_AUTHENTICATING, DEV_CONNECTED, DEV_RECONNECTING, DEV_ERROR } dev_state_t;
static volatile dev_state_t dev_state = DEV_IDLE;

void device_manager_handle(void) {
    switch (dev_state) {
    case DEV_IDLE:
        if (should_connect()) {
            connect_to_server();
            dev_state = DEV_CONNECTING;
        }
        break;

    case DEV_CONNECTING:
        if (connection_established()) dev_state = DEV_AUTHENTICATING;
        else if (connect_timeout()) dev_state = DEV_ERROR;
        break;

    case DEV_AUTHENTICATING:
        if (auth_success()) dev_state = DEV_CONNECTED;
        else if (++auth_retries > 3) dev_state = DEV_ERROR;
        break;

    case DEV_CONNECTED:
        if (data_available()) process_incoming_data();
        if (heartbeat_missed()) send_heartbeat();
        if (disconnect_requested()) { dev_state = DEV_IDLE; cleanup_resources(); }
        break;

    case DEV_RECONNECTING:
        if (reconnect_complete()) dev_state = DEV_AUTHENTICATING;
        break;

    case DEV_ERROR:
        log_error("Device error, resetting");
        dev_state = DEV_IDLE;
        break;
    }
}
